import { Text } from '@sonolus/core';
import { toServerItemInfo } from '../../models/server/items/info.js';
import { extractString } from '../../utils/extract.js';
import { handleError } from '../error.js';
export const createDefaultServerItemInfoHandler = (sonolus, group) => () => ({
    creates: group.creates,
    searches: group.searches,
    sections: [
        {
            title: { en: Text.Newest },
            itemType: group.type,
            items: group.items.slice(0, 5),
        },
    ],
    banner: sonolus.banner,
});
export const createServerItemInfoRouteHandler = (sonolus, group) => async ({ req, res, localize, ctx }) => {
    const response = await group.infoHandler({
        ...ctx,
        type: extractString(req.query.type),
    });
    if (handleError(response, res, localize))
        return;
    res.json(toServerItemInfo(sonolus, localize, response, group.creates, group.searches));
};
